      function CF_KRATHSH_ASTHENIASFormula return VARCHAR2 is
V_DISPLAY VARCHAR2(255);
V_DESCR VARCHAR2(255);

v_calc_begin_date_varchar	VARCHAR2(10);

CURSOR CUR_DESCR IS
SELECT TO_CHAR(a.PERCENTAGE)
FROM PEN_SICKNESS_DEDUCTIONS_NEW a
WHERE a.SICKNESS_DEDUCTION_ID = v_calc_begin_date_varchar
  and a.effective_date				= ( select max(b.effective_date)
                                  from PEN_SICKNESS_DEDUCTIONS_NEW b
                                 where b.SICKNESS_DEDUCTION_ID = a.SICKNESS_DEDUCTION_ID
                                   and b.effective_date <= :P_ACC_START_DATE );

begin
	IF :UPD_FLG=1 THEN
		V_DISPLAY:='ΚΑΙ ΧΩΡΙΣ ΚΡΑΤΗΣΗ ΑΣΘΕΝΕΙΑΣ. ';
	ELSE
	  v_calc_begin_date_varchar := Find_Fact_Sub_Death_Varchar(:P_Insured_Id_IND,:P_DT_DECISION_YEAR_SR,:P_DT_DEC_UNIT_CODE_SR,:P_DT_INCR_SEC_NO_SR, '1',
			 0,0,'00001','00159','00228');
			 
		IF  v_calc_begin_date_varchar  IS NULL THEN
		  v_calc_begin_date_varchar := Find_Fact_Sub_Death_Varchar(:P_Insured_Id_IND,:P_DT_DECISION_YEAR_SR,:P_DT_DEC_UNIT_CODE_SR,:P_DT_INCR_SEC_NO_SR, '1',
			 0,0,'00001','01069','00228');
		END IF;
		
		IF  v_calc_begin_date_varchar  IS NULL THEN
		  v_calc_begin_date_varchar := Find_Fact_Sub_Death_Varchar(:P_Insured_Id_IND,:P_DT_DECISION_YEAR_SR,:P_DT_DEC_UNIT_CODE_SR,:P_DT_INCR_SEC_NO_SR, '1',
			 0,0,'00001','00069','00228');
		END IF;
		
	END IF;
	
	IF v_calc_begin_date_varchar IS NOT NULL THEN
		OPEN CUR_DESCR;
		FETCH CUR_DESCR
		INTO V_DESCR;
		CLOSE CUR_DESCR;
		
		if nvl(V_DESCR,'0') = '0' then
			 V_DISPLAY:='ΚΑΙ ΧΩΡΙΣ ΚΡΑΤΗΣΗ ΑΣΘΕΝΕΙΑΣ. ';
		else
			 V_DISPLAY:='ΚΑΙ ΜΕ ΚΡΑΤΗΣΗ ΑΣΘΕΝΕΙΑΣ '||V_DESCR||'% .';
		end if;
	ELSE 
		V_DISPLAY:='ΚΑΙ ΜΕ ΚΡΑΤΗΣΗ ΑΣΘΕΝΕΙΑΣ 6%.';		 
	END IF;
	
/*		IF :CS_PERCENTAGE IS NOT NULL THEN
			V_DISPLAY:='ΚΑΙ ΜΕ ΚΡΑΤΗΣΗ ΑΣΘΕΝΕΙΑΣ '||:CS_PERCENTAGE||'% .';
		END IF;
		IF :CS_PERCENTAGE IS NULL THEN
			V_DISPLAY:='ΚΑΙ ΜΕ ΚΡΑΤΗΣΗ ΑΣΘΕΝΕΙΑΣ '||:CS_DEFAULT_PERC||'% .';
		END IF;
	END IF;
*/
	RETURN V_DISPLAY;
  
end;

/*
