      function CF_AMOUNTFormula return char is
begin
  IF :CALCULATION_FLG NOT IN ('1','6','11') OR :CALCULATION_FLG IS  NULL THEN
  	 RETURN LTRIM((TO_CHAR(:AMOUNT,'9999990D99')));
  ELSE
  	 RETURN :AMOUNT;
  END IF;
end;

function CF_IND_PRODUCTFormula return Char is
V_IND_PRODUCT_CODE PEN_PRODUCTS.PRODUCT_CODE%TYPE;
CURSOR cur_ind_account IS SELECT D.PRODUCT_CODE FROM PEN_ACCOUNT A, PEN_ACCOUNT B, PEN_QC_PER_PRODINST C, PEN_PRODUCT_PER_INSTITUTIONS D WHERE A.INS_INSURED_ID = B.INS_INSURED_ID AND B.ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR --SYSTEM DEAD_ACCOUNT_NO AND A.TEMP_FLG = '0' AND A.USAGE_FLG = '1' AND NVL(A.CONVERTED_FLG,'0') != '1' AND A.QCPRODINS_QC_PER_PRODINST_CODE = C.QC_PER_PRODINST_CODE AND C.PRODUCT_PER_INSTITUTION_CODE = D.PRODUCT_PER_INSTITUTION_CODE AND D.PRODUCT_CODE IN ('00001', '00002') /* CHRYS 29/11/2019 AND D.INSTITUTION_CODE = (SELECT H.INSTITUTION_CODE FROM PEN_ACCOUNT F, PEN_QC_PER_PRODINST G, PEN_PRODUCT_PER_INSTITUTIONS H WHERE F.QCPRODINS_QC_PER_PRODINST_CODE = G.QC_PER_PRODINST_CODE AND G.PRODUCT_PER_INSTITUTION_CODE = H.PRODUCT_PER_INSTITUTION_CODE AND F.ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR)
END CHRYS 29/11/2019 */ ;
begin OPEN cur_ind_account; FETCH cur_ind_account INTO V_IND_PRODUCT_CODE; CLOSE cur_ind_account;
RETURN V_IND_PRODUCT_CODE;
end;

      --function CF_10FORMULA0033 return Char is
function CF_PENSION_TYPE return Char is
begin
  IF :CF_IND_PRODUCT = '00002' THEN 
  	RETURN 'ΣΥΝΤΑΞΗ ΑΝΑΠΗΡΙΑΣ';
  ELSE
  	RETURN 'ΣΥΝΤΑΞΗ ΓΗΡΑΤΟΣ';
  END IF;	
  	
end;

function CF_DISABLED_PERCENTAGEFormula return Char is
V_INCR_SEQ_NO_SR PEN_QT_PER_BE_CC_PER_ACCOUNT.DI_DEC_INCR_SEQ_NO%TYPE; V_DECISION_YEAR_SR PEN_QT_PER_BE_CC_PER_ACCOUNT.DI_DT_DECISION_YEAR%TYPE; V_DEC_UNIT_CODE_SR PEN_QT_PER_BE_CC_PER_ACCOUNT.DI_DT_DEC_UNIT_CODE%TYPE; V_DI_DT_DOCUMENT_TYPE_SR PEN_QT_PER_BE_CC_PER_ACCOUNT.DI_DT_DOCUMENT_TYPE_DEC_CODE%TYPE; V_VALUE1 PEN_DEC_FACT_TYPES_INSTANCE.VALUE%TYPE;
V_INCR_SEQ_NO_SR2 PEN_ACCOUNT.DI_DEC_INCR_SEQ_NO%TYPE; V_DECISION_YEAR_SR2 PEN_ACCOUNT.DI_DT_DECISION_YEAR%TYPE; V_DEC_UNIT_CODE_SR2 PEN_ACCOUNT.DI_DT_DEC_UNIT_CODE%TYPE; V_DI_DT_DOCUMENT_TYPE_SR2 PEN_ACCOUNT.DI_DT_DOCUMENT_TYPE_DEC_CODE%TYPE; V_ACCOUNT_NO_DEAD PEN_ACCOUNT.ACCOUNT_NO%TYPE;
CURSOR cur_ind_account IS SELECT A.ACCOUNT_NO FROM PEN_ACCOUNT A, PEN_ACCOUNT B, PEN_QC_PER_PRODINST C, PEN_PRODUCT_PER_INSTITUTIONS D WHERE A.INS_INSURED_ID = B.INS_INSURED_ID AND B.ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR AND A.TEMP_FLG = '0' AND A.USAGE_FLG = '1' AND NVL(A.CONVERTED_FLG,'0') != '1' AND A.QCPRODINS_QC_PER_PRODINST_CODE = C.QC_PER_PRODINST_CODE AND C.PRODUCT_PER_INSTITUTION_CODE = D.PRODUCT_PER_INSTITUTION_CODE AND D.PRODUCT_CODE IN ('00001', '00002') AND D.INSTITUTION_CODE = (SELECT H.INSTITUTION_CODE FROM PEN_ACCOUNT F, PEN_QC_PER_PRODINST G, PEN_PRODUCT_PER_INSTITUTIONS H WHERE F.QCPRODINS_QC_PER_PRODINST_CODE = G.QC_PER_PRODINST_CODE AND G.PRODUCT_PER_INSTITUTION_CODE = H.PRODUCT_PER_INSTITUTION_CODE AND F.ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR);
Cursor cur_get_keys IS SELECT A.DI_DEC_INCR_SEQ_NO, A.DI_DT_DECISION_YEAR, A.DI_DT_DEC_UNIT_CODE, A.DI_DT_DOCUMENT_TYPE_DEC_CODE
FROM PEN_QT_PER_BE_CC_PER_ACCOUNT A ,PEN_QUALIFYING_TERM_PER_BE_CC B ,PEN_QUALIFYING_TERM_PER_CC C ,PEN_BE_PER_CALCUL_CATEGORY D ,PEN_BE_PER_QUAL_CAT F ,PEN_BE_PER_PRODINST G ,PEN_BUSSINESS_EVENTS H WHERE A.acc_account_no = V_ACCOUNT_NO_DEAD --a palios toy pethamenou AND A.cc_per_be_type_per_decins_upd = '1' AND A.status = '1' AND H.state = '0' AND H.bussiness_event_group = '19' AND A.commit_date IS NOT NULL AND A.bcc_qual_term_per_be_cc_code = B.qual_term_per_be_cc_code AND B.qualif_term_per_cc_code = C.qualif_term_per_cc_code AND C.be_per_calcul_category_co = D.be_per_calcul_category_code AND D.be_per_qual_category_code = F.be_per_qual_category_code AND F.be_per_prodinst_code = G.be_per_prodinst_code AND G.buss_event_code = H.buss_event_code ORDER BY A.commit_date DESC, a.START_DATE DESC ;
CURSOR cur_get_keys2 IS SELECT A.DI_DEC_INCR_SEQ_NO, A.DI_DT_DECISION_YEAR, A.DI_DT_DEC_UNIT_CODE, A.DI_DT_DOCUMENT_TYPE_DEC_CODE FROM PEN_ACCOUNT A WHERE A.ACCOUNT_NO = V_ACCOUNT_NO_DEAD;
CURSOR cur_value1 IS SELECT value FROM pen_dec_fact_types_instance WHERE pen_dec_fact_types_instance.ins_insured_id= :p_insured_id AND pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR = V_DI_DT_DOCUMENT_TYPE_SR AND pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR = V_INCR_SEQ_NO_SR AND pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = V_DECISION_YEAR_SR AND pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR = V_DEC_UNIT_CODE_SR AND pen_dec_fact_types_instance.dec_fact_type_code = '00200' and pen_dec_fact_types_instance.title_code ='00323';
CURSOR cur_value2 IS SELECT value FROM pen_dec_fact_types_instance WHERE pen_dec_fact_types_instance.ins_insured_id= :p_insured_id AND pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR = V_DI_DT_DOCUMENT_TYPE_SR2 AND pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR = V_INCR_SEQ_NO_SR2 AND pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = V_DECISION_YEAR_SR2 AND pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR = V_DEC_UNIT_CODE_SR2 AND pen_dec_fact_types_instance.dec_fact_type_code = '00200' and pen_dec_fact_types_instance.title_code ='00035';
begin
OPEN cur_ind_account; FETCH cur_ind_account INTO V_ACCOUNT_NO_DEAD; CLOSE cur_ind_account;
OPEN cur_get_keys; FETCH cur_get_keys INTO V_INCR_SEQ_NO_SR , V_DECISION_YEAR_SR , V_DEC_UNIT_CODE_SR , V_DI_DT_DOCUMENT_TYPE_SR; CLOSE cur_get_keys;
IF V_INCR_SEQ_NO_SR IS NOT NULL THEN OPEN cur_value1; FETCH cur_value1 INTO V_VALUE1; CLOSE cur_value1; ELSE OPEN cur_get_keys2; FETCH cur_get_keys2 INTO V_INCR_SEQ_NO_SR2, V_DECISION_YEAR_SR2, V_DEC_UNIT_CODE_SR2, V_DI_DT_DOCUMENT_TYPE_SR2; CLOSE cur_get_keys2;
OPEN cur_value2; FETCH cur_value2 INTO V_VALUE1; CLOSE cur_value2;
END IF;
RETURN (100-TO_NUMBER(V_VALUE1) || '%'); end;

      function CF_267 return CHAR is
begin
    IF :P_FACTITIOUS_DATE >= '1/1/2003' THEN 
  	RETURN ('267Α');
  ELSE 
  	RETURN ('200στά');
  END IF;
end;

      function CF_10FORMULA0022 return Char is

--V_VALUE PEN_DEC_FACT_TYPES_INSTANCE.VALUE%TYPE;
V_REAL_ACCOUNT_NO PEN_ACCOUNT.ACCOUNT_NO%TYPE;
V_REDUCTION  NUMBER;
V_UNDER NUMBER;

CURSOR CUR_VALUE IS
SELECT NVL(FIND_DEAD_REAL_ACCOUNT(:P_ACC_ACCOUNT_NO_DIR),:P_ACC_ACCOUNT_NO_DIR)
FROM DUAL;

/*CURSOR CUR_VALUE is
SELECT value FROM pen_dec_fact_types_instance
WHERE pen_dec_fact_types_instance.title_code IN ('00070', '00071') AND 
pen_dec_fact_types_instance.ins_insured_id= :p_insured_id AND 
pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR ='1'  AND 
pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR =  :P_DT_INCR_SEC_NO_SR AND 
pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :p_dt_decision_year AND 
pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR =  :p_dt_dec_unit_code AND 
pen_dec_fact_types_instance.dec_fact_type_code = '00119';*/



begin
  
  OPEN  CUR_VALUE;
  FETCH CUR_VALUE
  INTO V_REAL_ACCOUNT_NO;
  CLOSE CUR_VALUE;

  PENBAT_IKA_CP_PROCEDURES.PENSION_REDUCTION(V_REAL_ACCOUNT_NO,0,1000,V_REDUCTION); 
   IF :P_FACTITIOUS_DATE >= '1/1/2003' THEN 
  	 V_UNDER:= 267;
  ELSE 
  	 V_UNDER:= 200;
  END IF;
  
  V_REDUCTION:= ROUND((V_UNDER/1000)*V_REDUCTION);
  
  RETURN V_REDUCTION;
  
end;

