      function CF_work_end_dateFormula return Char is
to_return varchar2(500);
v_end_date      varchar2(60);

cursor Cur_Fact_Subtype_Existance IS 
  select distinct pen_dec_fact_types_instance.value
  from  pen_dec_fact_types_instance
WHERE pen_dec_fact_types_instance.title_code='00019' AND 
pen_dec_fact_types_instance.ins_insured_id=  :P_INSURED_ID_IND AND 
pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR ='1'  AND 
pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR =  :P_DT_INCR_SEC_NO_SR  AND 
pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR_SR  AND 
pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR =  :P_DT_DEC_UNIT_CODE_SR AND
pen_dec_fact_types_instance.dec_fact_type_code = '00588';
  

begin
	to_return :='';
	v_end_date:=null;
	   open Cur_Fact_Subtype_Existance;
     fetch Cur_Fact_Subtype_Existance into v_end_date;
     close Cur_Fact_Subtype_Existance;                                              
    if v_end_date is not null then
    	 :CP_EXT_WRK_DATE:=1;
    	 to_Return:='ΗΜΕΡΟΜΗΝΙΑ ΔΙΑΚΟΠΗΣ ΕΡΓΑΣΙΑΣ:'||v_end_date;
    ELSE
    	:CP_EXT_WRK_DATE:=0;
    end if;
   return to_Return;
end;

