      function CF_24Formula return Number is


v_DESCR  NUMBER;
v_calc_begin_date_varchar   VARCHAR2(10);

CURSOR cur_pension_type IS
SELECT 100 - PRCN
FROM PEN_ACC_DISAB_DECREMENT_PRCN
WHERE  ACC_ACCOUNT_NO = v_calc_begin_date_varchar;

begin

v_calc_begin_date_varchar := Find_Fact_Sub_Death_Varchar(:P_INSURED_ID,:P_DT_DECISION_YEAR_DIR,:P_DT_DEC_UNIT_CODE_DIR,:P_DT_INCR_SEC_NO_DIR, '1',
            0,0,'00001','01181','01127');




  open cur_pension_type;
  fetch cur_pension_type
  into v_DESCR;
  close cur_pension_type;
  
  
   -- CHRYS 23/6/2020 IF V_DESCR IS NOT NULL THEN
   	IF NVL(V_DESCR,0) != 0 THEN -- CHRYS 23/6/2020
     RETURN V_DESCR;
   ELSE
    -- CHRYS 22/6/2020
    v_calc_begin_date_varchar := Find_Fact_Sub_Death_Varchar(:P_INSURED_ID,:P_DT_DECISION_YEAR_DIR,:P_DT_DEC_UNIT_CODE_DIR,:P_DT_INCR_SEC_NO_DIR, '1',
            0,0,'00001','01639','00508'); -- ΜΕΙΩΣΗ ΠΟΣΟΣΥ ΣΥΤΝΑΞΗΣ ΑΝΑΠΗΡΙΑΣ ΑΠΟ 
    -- END CHRYS 22/6/2020
    -- CHRYS 23/6/2020 IF v_calc_begin_date_varchar IS NOT NULL THEN
    	IF NVL(v_calc_begin_date_varchar,'0') != '0' THEN -- CHRYS 23/6/2020
    	RETURN v_calc_begin_date_varchar;
    ELSE
    	RETURN NULL;
    END IF;
   END IF;     		
end;

      function CF_25Formula return VARCHAR is

/*v_DESCR  VARCHAR2(20);-- CHRYS 7/8/2017
v_calc_begin_date_varchar   VARCHAR2(10);
v_calc_begin_date_varchar_1 VARCHAR2(10);

CURSOR cur_pension_type IS
SELECT MONTHS_GAP||'/'||DENOMINATOR	-- CHRYS 7/8/2017
FROM PEN_ACCOUNT_AGE_REDUCTION
WHERE  ACCOUNT_NO = v_calc_begin_date_varchar;

begin

v_calc_begin_date_varchar := Find_Fact_Sub_Death_Varchar(:P_INSURED_ID,:P_DT_DECISION_YEAR_DIR,:P_DT_DEC_UNIT_CODE_DIR,:P_DT_INCR_SEC_NO_DIR, '1',
            0,0,'00001','01181','01127');

   
v_calc_begin_date_varchar_1 := Find_Fact_Sub_Death_Varchar(:P_INSURED_ID,:P_DT_DECISION_YEAR_DIR,:P_DT_DEC_UNIT_CODE_DIR,:P_DT_INCR_SEC_NO_DIR, '1',
            0,0,'00001','01636','00653');

  open cur_pension_type;
  fetch cur_pension_type
  into v_DESCR;
  close cur_pension_type;
   
  
   IF V_DESCR IS NOT NULL THEN
     RETURN V_DESCR;
   ELSE
    RETURN v_calc_begin_date_varchar_1;
   END IF;
   
    IF  V_DESCR IS NULL AND v_calc_begin_date_varchar_1 IS NULL THEN
   	RETURN NULL;
   END IF;
   
end;*/
-----------------------------------------------------------------------
v_DESCR  VARCHAR2(20);-- CHRYS 7/8/2017
v_calc_begin_date_varchar   VARCHAR2(10);
v_calc_begin_date_reduct		VARCHAR2(10);

V_DENOM NUMBER;
V_AGE_LIMIT_REDUCTION NUMBER;
V_REDUCTION_FRACTION  VARCHAR2(20);

CURSOR CUR_AGE_REDUCT_METAV IS
SELECT TO_CHAR(MONTHS_GAP)||'/'||TO_CHAR(DENOMINATOR)	-- CHRYS 7/8/2017
FROM PEN_ACCOUNT_AGE_REDUCTION
WHERE  ACCOUNT_NO = v_calc_begin_date_reduct;


CURSOR AGE_LIMIT_REDUCT_DENOM IS 
SELECT DISTINCT -- CHRYS 12/6/2020 AGE_LIMIT_REDUCTION
			ROUND(AGE_LIMIT_REDUCTION,5) -- CHRYS 12/6/2020
FROM PEN_CALC_NATIONAL_RESULTS
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR;

/*CURSOR AGE_LIMIT_REDUCT IS 
SELECT DISTINCT AGE_LIMIT_REDUCTION
FROM PEN_CALC_NATIONAL_RESULTS
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR;
 */
 V_START_DATE_PREVIOUS_CHAR		VARCHAR2(20); -- CHRYS 17/6/2020
 V_START_DATE_PREVIOUS				DATE; -- CHRYS 17/6/2020

 -- CHRYS 11/6/2020
 CURSOR cur_age_reduction_denom_sub IS
SELECT denominator
FROM PEN_AGE_REDUCTION_DENOM
WHERE VALIDITY_DATE <= V_START_DATE_PREVIOUS -- CHRYS 17/6/2020 :P_ACC_START_DATE
ORDER BY VALIDITY_DATE DESC;

V_DENOMINATOR_2		NUMBER;
 -- END CHRYS 11/6/2020
 -- END CHRYS 11/6/2020

begin
	--COMBAT_dEBUGING('P_ACC_ACCOUNT_NO_DIR = '||:P_ACC_ACCOUNT_NO_DIR, 'CHRYS_1206');
	--COMBAT_dEBUGING('P_DT_DECISION_YEAR_DIR = '||:P_DT_DECISION_YEAR_DIR, 'CHRYS_1206');
	--COMBAT_dEBUGING('P_DT_DEC_UNIT_CODE_DIR = '||:P_DT_DEC_UNIT_CODE_DIR, 'CHRYS_1206');
	--COMBAT_dEBUGING('P_DT_INCR_SEC_NO_DIR = '||:P_DT_INCR_SEC_NO_DIR, 'CHRYS_1206');
	--COMBAT_dEBUGING('P_INSURED_ID = '||:P_INSURED_ID, 'CHRYS_1206');
/* CHRYS 12/6/2020 ΠΕΡΝΑΩ ΤΙΣ ΑΛΛΑΓΕΣ ΤΗΣ HDIKA_DEATH_AUTO 	
	
COMBAT_dEBUGING('IN TH FORMUL 25', 'CHRYS_2905');
v_calc_begin_date_varchar := Find_Fact_Sub_Death_Varchar(:P_INSURED_ID,:P_DT_DECISION_YEAR_DIR,:P_DT_DEC_UNIT_CODE_DIR,:P_DT_INCR_SEC_NO_DIR, '1',
            0,0,'00001','01636','00653');

v_calc_begin_date_reduct := Find_Fact_Sub_Death_Varchar(:P_INSURED_ID,:P_DT_DECISION_YEAR_DIR,:P_DT_DEC_UNIT_CODE_DIR,:P_DT_INCR_SEC_NO_DIR, '1',
            0,0,'00001','01181','01127');

OPEN 		CUR_AGE_REDUCT_METAV;
FETCH		CUR_AGE_REDUCT_METAV
INTO		V_REDUCTION_FRACTION;
CLOSE 	CUR_AGE_REDUCT_METAV;


IF V_REDUCTION_FRACTION IS NULL THEN
	OPEN AGE_LIMIT_REDUCT_DENOM;
	FETCH AGE_LIMIT_REDUCT_DENOM
	INTO V_AGE_LIMIT_REDUCTION;
	
	IF AGE_LIMIT_REDUCT_DENOM%FOUND THEN
		IF V_AGE_LIMIT_REDUCTION != 0 THEN -- CHRYS 7/12/2017
			V_DENOM := ROUND(TO_NUMBER(v_calc_begin_date_varchar)/V_AGE_LIMIT_REDUCTION);
			-- CHRYS 29/5/2020 V_REDUCTION_FRACTION := v_calc_begin_date_varchar||'/'||TO_CHAR(V_DENOM);
			-- CHRYS 12/6/2020 V_REDUCTION_FRACTION :=    V_AGE_LIMIT_REDUCTION; -- CHRYS 29/5/2020
      V_REDUCTION_FRACTION :=   TO_CHAR( V_AGE_LIMIT_REDUCTION); -- CHRYS 12/6/2020
		ELSE	
			V_REDUCTION_FRACTION := 0;
		END IF;
	ELSE
			V_DENOM := 200;
			V_REDUCTION_FRACTION := v_calc_begin_date_varchar||'/'||TO_CHAR(V_DENOM);
	END IF;
	CLOSE AGE_LIMIT_REDUCT_DENOM;
END IF;
RETURN V_REDUCTION_FRACTION;

END CHRYS 12/6/2020 ΠΕΡΝΑΩ ΤΙΣ ΑΛΛΑΓΕΣ ΤΗΣ HDIKA_DEATH_AUTO */


-- CHRYS 11/6/2020

--1. ΕΑΝ ΥΠΑΡΧΕΙ Η ΜΕΙΩΣΗ ΣΤΟ ΛΟΓΑΡΙΑΣΜΟ ΓΗΡΑΤΟΣ ΠΟΥ ΜΕΤΑΒΙΒΑΖΕΤΑΙ
--1.a ΒΡΙΣΚΩ ΤΟ ΜΕΤΑΒΙΒΑΖΟΜΕΝΟ ΛΟΓΑΡΙΑΣΜΟ
v_calc_begin_date_reduct := Find_Fact_Sub_Death_Varchar(:P_INSURED_ID,:P_DT_DECISION_YEAR_DIR,:P_DT_DEC_UNIT_CODE_DIR,:P_DT_INCR_SEC_NO_DIR, '1',
            0,0,'00001','01181','01127');

-- CHRYS 17/6/2020
V_START_DATE_PREVIOUS_CHAR := Find_Fact_Sub_Death_Varchar(:P_INSURED_ID,:P_DT_DECISION_YEAR_DIR,:P_DT_DEC_UNIT_CODE_DIR,:P_DT_INCR_SEC_NO_DIR, '1',
            0,0,'00001','01180','00662');
IF V_START_DATE_PREVIOUS_CHAR IS NULL THEN
	V_START_DATE_PREVIOUS_CHAR := Find_Fact_Sub_Death_Varchar(:P_INSURED_ID,:P_DT_DECISION_YEAR_DIR,:P_DT_DEC_UNIT_CODE_DIR,:P_DT_INCR_SEC_NO_DIR, '1',
            0,0,'00001','01639','00506');
END IF;

IF V_START_DATE_PREVIOUS_CHAR IS NOT NULL THEN
	V_START_DATE_PREVIOUS := TO_DATE(V_START_DATE_PREVIOUS_CHAR, 'DD/MM/RRRR');
END IF;
COMBAT_dEBUGING('V_START_DATE_PREVIOUS_CHAR := '||V_START_DATE_PREVIOUS_CHAR, 'CHRYS_170620'); 
-- END CHRYS 17/6/2020

OPEN 		CUR_AGE_REDUCT_METAV;
FETCH		CUR_AGE_REDUCT_METAV
INTO		V_REDUCTION_FRACTION;
CLOSE 	CUR_AGE_REDUCT_METAV;
 
IF V_REDUCTION_FRACTION IS NOT NULL THEN
	RETURN (V_REDUCTION_FRACTION);
END IF;

--2. ΠΑΙΡΙΝΩ ΤΗ ΜΕΙΩΣΗ ΑΠΟ ΤΑ ΑΠΟΤΕΛΕΣΜΑΤΑ ΥΠΟΛΟΓΙΣΜΟΥ ΕΘΝΙΚΗΣ
	OPEN AGE_LIMIT_REDUCT_DENOM;
	FETCH AGE_LIMIT_REDUCT_DENOM
	INTO V_AGE_LIMIT_REDUCTION;

	--2.α. ΒΡΣΙΚΩ ΤΗ ΜΕΙΩΣΗ ΟΠΩΣ ΕΧΕΙ ΚΑΤΑΧΩΡΗΘΕΙ ΣΕ SPECIAL FACT -- ΕΑΝ ΥΠΑΡΧΕΙ
	v_calc_begin_date_varchar := Find_Fact_Sub_Death_Varchar(:P_INSURED_ID,:P_DT_DECISION_YEAR_DIR,:P_DT_DEC_UNIT_CODE_DIR,:P_DT_INCR_SEC_NO_DIR, '1',
            0,0,'00001','01636','00653');
  
	--2.β ΒΡΣΙΚΩ ΤΟΝ ΠΑΡΟΝΟΜΑΣΤΗ ΠΟΥ ΕΞΑΡΤΑΤΑΙ ΑΠΟ ΤΗΝ ΕΝΑΡΞΗ ΤΗΣ ΣΥΝΤΑΞΗΣ
	OPEN cur_age_reduction_denom_sub;
  FETCH cur_age_reduction_denom_sub
  INTO V_DENOMINATOR_2;
  IF cur_age_reduction_denom_sub%NOTFOUND THEN
  	V_DENOMINATOR_2 := 200;
  END IF;
  CLOSE cur_age_reduction_denom_sub;
	IF NVL(V_AGE_LIMIT_REDUCTION,0) = 0 THEN 
		RETURN (NULL); -- CHRYS 12/6/2020 TO_CHAR ((NVL(V_AGE_LIMIT_REDUCTION,0)));
	END IF;
	
	IF NVL(V_AGE_LIMIT_REDUCTION,0) != 0 THEN 
			IF v_calc_begin_date_varchar IS NOT NULL THEN --ΕΑΝ ΕΧΩ SPECIAL FACT, ΘΑ ΒΡΩ ΤΟΝ ΠΑΡΟΝΟΜΑΣΤΗ ΜΕ ΧΡΗΣΗ ΤΟΥ SPECIAL FACT 
				V_DENOM := ROUND(TO_NUMBER(v_calc_begin_date_varchar)/V_AGE_LIMIT_REDUCTION);
				V_REDUCTION_FRACTION := v_calc_begin_date_varchar||'/'||TO_CHAR(V_DENOM);
				RETURN (V_REDUCTION_FRACTION);
			ELSE -- ΑΝ ΔΕΝ ΕΧΩ SPECIAL FACT ΘΑ ΒΡΩ ΤΟΝ ΠΑΡΟΝΟΜΑΣΤΗ ΜΕ ΧΡΗΣΗ ΤΟΥ ΠΙΝΑΚΑ ΠΟΥ ΔΙΝΕΙ ΤΟΝ ΠΑΡΟΝΟΜΑΣΤΗ ΑΝΑ ΗΜΕΡΟΜΗΝΙΑ ΕΝΑΡΞΗΣ ΣΥΝΤΑΞΗΣ
				V_DENOM := V_DENOMINATOR_2;
				-- CHRYS 17/6/2020 V_REDUCTION_FRACTION := TO_CHAR(V_AGE_LIMIT_REDUCTION*V_DENOM)||'/'||TO_CHAR(V_DENOM);
				V_REDUCTION_FRACTION := TO_CHAR(ROUND(V_AGE_LIMIT_REDUCTION*V_DENOM))||'/'||TO_CHAR(V_DENOM); -- CHRYS 17/6/2020
				RETURN (V_REDUCTION_FRACTION);
			END IF;
	END IF;
	
	RETURN ('');
-- END CHRYS 11/6/2020   

   

END ;

