      function CF_SYNOLO_ETHNIKI_ADAPFormula return Number is
FINAL_NAT_PENSION_AMT_MEMBER NUMBER;
FINAL_NAT_PENSION_AMT_DEC    NUMBER;
ADAPODOTIKH_AMT_MEMBER       NUMBER;
ADAPODOTIKH_AMT_DEC          NUMBER;
begin

	SELECT  FINAL_NAT_PENSION_AMT ,
          FINAL_NAT_PENSION_AMT*(:P_PERCENTAGE/100) 
     INTO FINAL_NAT_PENSION_AMT_DEC,
          FINAL_NAT_PENSION_AMT_MEMBER
		FROM  PEN_CALC_NATIONAL_RESULTS
		WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR
		;

  SELECT DISTINCT ADAPODOTIKH_AMT ,
                  ADAPODOTIKH_AMT*(:P_PERCENTAGE/100)  
             INTO ADAPODOTIKH_AMT_DEC, 
                  ADAPODOTIKH_AMT_MEMBER
    FROM PEN_CALC_ADAPOD_RESULTS
    WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR
    ;
  
  :CP_SUM_EA_DEC    :=  NVL(FINAL_NAT_PENSION_AMT_DEC,0)    +  NVL(ADAPODOTIKH_AMT_DEC,0);
  :CP_SUM_EA_MEMBER :=  NVL(FINAL_NAT_PENSION_AMT_MEMBER,0) +  NVL(ADAPODOTIKH_AMT_MEMBER,0);

  RETURN (:CP_SUM_EA_DEC);
  EXCEPTION WHEN OTHERS THEN RETURN 0; 

end;

function CF_TOY_THSFormula return Char is
l_toy_ths varchar2(100); l_toy_ths2 varchar2(100); begin SELECT DECODE(a.SEX,'Α','του ','Θ','της ') TOY_THS INTO l_toy_ths FROM REG_INSURED a WHERE a.INSURED_ID = :P_INSURED_ID_IND ;
SELECT DECODE(REG_INSURED.SEX,'Α','του Θανόντα ','Θ','της Θανούσης') THANONTAS_THANOUSI INTO l_toy_ths2 FROM REG_INSURED, PEN_APPLICATION_INSTANCES, COM_ORG_BRANCHES, PEN_BE_PER_PRODINST, PEN_PRODUCT_PER_INSTITUTIONS, PEN_PRODUCTS, COM_PENSION_IKA_INSTITUTION WHERE PEN_APPLICATION_INSTANCES.APPLICATION_INCR_SEQ_NO=:P_APPL_INCR_SEQ_NO AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_UNIT_CODE=:P_APPL_UNIT_CODE AND PEN_APPLICATION_INSTANCES.PDTA_DOCUMENT_TYPE_APPL_CODE='00001' AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_YEAR=:P_APPL_YEAR AND PEN_APPLICATION_INSTANCES.INSURED_ID=:P_INSURED_ID AND REG_INSURED.INSURED_ID=PEN_APPLICATION_INSTANCES.INSURED_ID AND PEN_BE_PER_PRODINST.BE_PER_PRODINST_CODE=:P_BE_PER_PRODINST AND PEN_BE_PER_PRODINST.PRODUCT_PER_INSTITUTION_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_PER_INSTITUTION_CODE AND COM_PENSION_IKA_INSTITUTION.PENSION_IKA_INST_CODE=PEN_PRODUCT_PER_INSTITUTIONS.INSTITUTION_CODE AND PEN_PRODUCTS.PRODUCT_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_CODE AND COM_ORG_BRANCHES.BRANCH_CODE=:P_DT_DEC_UNIT_CODE_SR;
:CP_TOY_THS := l_toy_ths; :CP_TOY_THS2 := l_toy_ths2; return (:CP_TOY_THS); EXCEPTION WHEN OTHERS THEN RETURN NULL; end;

