      function CF_AWARD_PROMPTFormula return Char is

V_AWARD_FLAG VARCHAR2(1);
V_PROMPT     VARCHAR2(100);

Cursor cur_award_prompt Is
 SELECT A.AWARD_TYPE_FLAG
FROM PEN_DECISION_INSTANCE A										 
WHERE A.DEC_INCR_SEQ_NO =:P_DEC_INCR_SEC_NO
AND A.DT_DEC_UNIT_CODE=:P_DT_DEC_UNIT_CODE
AND A.DT_DECISION_YEAR=:P_DT_DECISION_YEAR
AND A.DT_DOCUMENT_TYPE_DEC_CODE='1';

cursor Find_Conv_account is
SELECT pen_dec_fact_types_instance.VALUE
FROM pen_dec_fact_types_instance
WHERE pen_dec_fact_types_instance.title_code='00318' AND 
pen_dec_fact_types_instance.dec_fact_type_code = '00341' AND
PEN_DEC_FACT_TYPES_INSTANCE.DI_DEC_INCR_SEQ_NO_SR =  :P_DT_INCR_SEC_NO_SR AND
PEN_DEC_FACT_TYPES_INSTANCE.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR_SR  AND
PEN_DEC_FACT_TYPES_INSTANCE.DI_DEC_UNIT_CODE_SR =  :P_DT_DEC_UNIT_CODE_SR AND
PEN_DEC_FACT_TYPES_INSTANCE.DI_DOCUMENT_TYPE_DEC_COCE_SR = '1' AND
PEN_DEC_FACT_TYPES_INSTANCE.INS_INSURED_ID = :P_INSURED_ID_IND 
;

cursor find_conv_decision(v_account_no number) is
Select A.Dt_Dec_Unit_Code||'/'||A.Dt_Decision_Year||'/'||A.Dec_Incr_Seq_No||'-'||TO_CHAR(A.LAST_PRINT_TIME_DEC, 'DD/MM/RRRR')
--ALKA 17012014 A.Payment_Start_Date
From Pen_Decision_Instance A,
     Pen_Account B
Where A.Document_Type_Dec_Code_Sr =B.Di_Dt_Document_Type_Dec_Code
And A.Dec_Unit_Code_Sr=B.Di_Dt_Dec_Unit_Code
And A.Decision_Year_Sr=B.Di_Dt_Decision_Year
And A.Incr_Seq_No_Sr=B.Di_Dec_Incr_Seq_No
And B.Account_No =v_account_no
;
v_conv_account number;
v_conv_decision varchar2(50);

begin
 
 OPEN cur_award_prompt;
   FETCH cur_award_prompt 
   INTO V_AWARD_FLAG;
 CLOSE cur_award_prompt;
 :CP_AWARD_TYPE:=V_AWARD_FLAG;
 IF V_AWARD_FLAG IN ('0','1','2') THEN
 	  V_PROMPT:='Απονομής';
 ELSIF V_AWARD_FLAG IN ('3','4') THEN
 	    V_PROMPT:='Παράτασης';
 ELSIF V_AWARD_FLAG IN ('8') THEN
 	   open Find_Conv_account;
 	  fetch Find_Conv_account into v_conv_account;
 	  close Find_Conv_account;
 	  open find_conv_decision(v_conv_account);
 	  fetch find_conv_decision into v_conv_decision;
 	  close find_conv_decision;
 	  --:CP_CONV_DECISION:=v_conv_decision;
 	  V_PROMPT:='( απόφαση:'||v_conv_decision||' )';--'τροποποίησης της απόφασης';
 	END IF;
 
 RETURN V_PROMPT;
 
end;

      function CF_ALLES_SYNTAKSEISFormula return Char is
  results             Web_auto_pen_recalc.tab_results;
  p_check_number      Number;
  p_check_description Varchar2(2000);
  p_errno             Number;
  p_errtxt            Varchar2(2000);
  p_date              Date         := :DATE_OF_DEATH; --trunc(sysdate);
  p_amka_id           Varchar2(20) := :AMKA_ID1;
  p_taxation_id       Varchar2(20) := :TAXATION_ID1; 
  eseps_description   Varchar2(200);
  am_in_institution   Varchar2(50); 
  Product_Description Varchar2(200); 
  j                   Number := 0;
  l_string					  Varchar2(2000) := 'Αλλες Συντάξεις';
begin
  -- Call the procedure
  workflow.web_auto_pen_recalc.web_auto_pen_recalc_info(p_date              => p_date,
                                                        p_amka_id           => p_amka_id,
                                                        p_taxation_id       => p_taxation_id,
                                                        results             => results,
                                                        p_check_number      => p_check_number,
                                                        p_check_description => p_check_description,
                                                        p_errno             => p_errno,
                                                        p_errtxt            => p_errtxt);

  
  j := 1; 
  for j in 1..results.count loop
    eseps_description   := results(j).eseps_description;
    am_in_institution   := results(j).am_in_institution;
    Product_Description := results(j).Product_Description; 
    --dbms_output.put_line(' eseps_description  :' ||eseps_description); 
    --dbms_output.put_line(' am_in_institution   :' ||am_in_institution); 
    --dbms_output.put_line(' Product_Description :' ||Product_Description); 
    l_string := l_string||' [Φορέας : '||eseps_description||' -A.M. Φορέα : '|| am_in_institution ||' -Kατηγορία Σύνταξης : '||Product_Description||']'||chr(10);
  end loop;
  
  return(l_string);
  exception when others then return null;
end;

